import React,{useState,useEffect} from "react";
import "./App.css";
import "./index.css";

import {Bar, Doughnut } from "react-chartjs-2";
//import SubscriptionForm from "./SubscriptionForm";
//import Dashboard from "./Dashboard";
import SpendingChart from "./SpendingChart";
import PiggyBank from "./PiggyBank"; 


import {
Chart as ChartJS,
CategoryScale,
LinearScale,
BarElement,
ArcElement,
Title,
Tooltip,
Legend
} from "chart.js";

ChartJS.register(
CategoryScale,
LinearScale,
BarElement,
ArcElement,
Title,
Tooltip,
Legend
);

function App(){

const [transactions,setTransactions] = useState([]);
const [amount,setAmount] = useState("");
const todaySavings=transactions.reduce((total,t)=>total + t.saved, 0).toFixed(2);
const [subscriptions, setSubscriptions] = useState([]);
const [loading, setLoading] = useState(false);

useEffect(()=>{
fetchTransactions();
fetchSubscriptions();
},[]);

const fetchTransactions = async () => {
  const res = await fetch("http://localhost:5000/transactions");
  const data = await res.json();
  setTransactions(data);
};

const fetchSubscriptions = async () => {
    setLoading(true);
  try {
    const res = await fetch("http://localhost:5000/subscriptions");
    const data = await res.json();
    setSubscriptions(data);
  } catch (err) {
    console.log(err);
  }
   setLoading(false);
};

const addTransaction = async () =>{

    if (!amount || isNaN(amount)) {
  alert("Enter valid amount");
  return;
}

const res = await fetch("http://localhost:5000/transaction",{


method:"POST",
headers:{
"Content-Type":"application/json"
},
body:JSON.stringify({amount})

});

await res.json();

setAmount("");

fetchTransactions();

if (res.ok) {
  setAmount("");
  fetchTransactions();
  alert("Transaction Added Successfully!");
} else {
  alert("Failed to add transaction.");
}

}

const clearTransactions =async () => {
    await fetch("http://localhost:5000/clear",{
        method:"DELETE" 
    });
fetchTransactions();

try {
  await fetch("http://localhost:5000/clear", { method: "DELETE" });
  fetchTransactions();
} catch(err) {
  console.error(err);
  alert("Failed to clear transactions");
}
}

const totalSavings =
transactions.reduce((sum,t)=>sum + t.saved,0);

const chartData = {
labels: transactions.map((t,i)=>"T"+(i+1)),
datasets:[
{
label:"Savings",
data: transactions.map(t=>t.saved),
backgroundColor: "#0e652e"
}
]
};

const goal = 1000;

const goalData = {
  labels: ["Saved", "Remaining"],
  datasets: [
    {
      data: [totalSavings, Math.max(goal - totalSavings, 0)],
      backgroundColor: ["#22c55e", "#e5e7eb"],
    },
  ],
};

const progress =(totalSavings/goal)*100;

const getAdvice = () => {
  if (totalSavings < 100) {
    return "Try saving small amounts daily to build your habit.";
  } 
  else if (totalSavings < 500) {
    return "Great start! Consider setting a weekly savings goal.";
  } 
  else {
    return "Excellent! You are building strong financial discipline.";
  }
};

return (
<div className="flex min-h-screen bg-gray-100">

{/* Sidebar */}
<div className="w-64 bg-gray-900 text-white p-6">

<h2 className="text-2xl font-bold mb-10">Smart Savings</h2>

<ul className="space-y-4 text-gray-300">

<li className="hover:text-white cursor-pointer">Dashboard</li>
<li className="hover:text-white cursor-pointer">Transactions</li>
<li className="hover:text-white cursor-pointer">Analytics</li>

</ul>

</div>

<div className="flex-1">

{/* Navbar */}
<div className="bg-white shadow p-4 flex justify-between items-center">

<h2 className="text-xl font-semibold">Smart Savings Dashboard</h2>

<div className="text-gray-600">Welcome User</div>

</div>

<div className="p-6">
  {loading && <p className="text-gray-600 text-lg mb-4">Loading...</p>}

  <h1 className="text-3xl font-bold mb-6">Dashboard</h1>

  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
    {/* Your cards */}
  </div>
</div>

<div className="p-6">

<h1 className="text-3xl font-bold mb-6">Dashboard</h1>
   <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">

<div className="bg-white rounded-xl shadow p-5">
<h3 className="text-gray-500">Total Savings</h3>
<h1 className="text-3xl font-bold text-green-500">₹{totalSavings.toFixed(2)}</h1>
</div>

<div className="bg-white rounded-xl shadow p-5">
<h3 className="text-gray-500">Transactions</h3>
<h1 className="text-3xl font-bold">{transactions.length}</h1>
</div>

<div className="bg-white rounded-xl shadow p-5">
<h3 className="text-gray-500">Today's Savings</h3>
<h1 className="text-3xl font-bold text-blue-500">₹{todaySavings}</h1>
</div>

<div className="bg-white rounded-xl shadow p-5">
<h3 className="text-gray-500">AI Advisor</h3>
<p className="text-gray-600">{getAdvice()}</p>
</div>
  <PiggyBank totalSavings={totalSavings} goal={goal} />

<div className="mt-4">
  <p className="text-gray-600 mb-1">Goal Progress: {progress.toFixed(2)}%</p>
  <div className="w-full bg-gray-300 rounded-full h-4">
    <div
      className="bg-green-500 h-4 rounded-full"
      style={{ width: `${progress}%` }}
    ></div>
  </div>


</div>

</div>
    <div className="grid md:grid-cols-2 gap-6 mb-8">

<div className="bg-white rounded-xl shadow p-6">
<h3 className="text-lg font-semibold mb-4">Savings Overview</h3>
<Bar data={chartData}/>
</div>

<div className="bg-white rounded-xl shadow p-6">
<h3 className="text-lg font-semibold mb-4">Goal Tracker</h3>
<Doughnut data={goalData}/>

</div>

</div>
    <div className="bg-white rounded-xl shadow p-6 mb-8">

<h3 className="text-lg font-semibold mb-4">Add Transaction</h3>

<input
className="border p-2 rounded mr-2"
type="number"
placeholder="Enter transaction"
value={amount}
onChange={(e)=>setAmount(e.target.value)}
/>

<button
className="bg-green-500 text-white px-4 py-2 rounded mr-2"
onClick={addTransaction}
>
Add
</button>

<button
className="bg-red-500 text-white px-4 py-2 rounded"
onClick={clearTransactions}
>
Clear
</button>

</div>

</div>
</div>
</div>
)

}

export default App;
